import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { VisuallyHidden } from '@andes/visually-hidden';
import { useId } from '@andes/context';
import PillIcon from './PillIcon';
import computeColorProps from './utils/computeColorProps';
import includes from '@andes/common/build/utils/includes';
import { WARNING_COLORS, WARNING_CONTENT_TYPE } from './constants/warnings';
import {
  CONTENT_TYPE,
  DEPRECATED_BADGE_COLORS,
  namespace,
  PILL_TYPE_ICON,
  ROUNDED_CORNERS_VALUES,
} from './constants';
import { useThemeContext } from '@andes/themes';
import warning from '@andes/common/build/utils/warning';

/** @typedef {import('..').PillSpecificProps} PillPublicProps */

/**
 * @typedef {Object} PillInternalProps
 * @prop {PillPublicProps['size'] | 'xsmall'} [size]
*/

/** @typedef {PillPublicProps & PillInternalProps} PillProps */

/**
 * Badges are used to indicate an status or to differentiate an element, block or content from others.
 */
/** @type {React.FunctionComponent<PillProps>} */
const Pill = (props) => {
  const {
    children,
    className,
    color,
    hierarchy = 'loud',
    contentType: _willdeprecate$contentType,
    id,
    roundedCorners = ROUNDED_CORNERS_VALUES,
    secondaryColor,
    size = 'large',
    srLabel,
    ref,
    backgroundType,
    customVariant,
    ...otherProps
  } = props;

  // @deprecate [contentType] - Warning from: 9.0.0
  warning(typeof _willdeprecate$contentType === 'undefined', WARNING_CONTENT_TYPE);

  // @deprecate [color] options: ['accent', 'gray', 'green', 'orange', 'red'] - Warning from: 9.0.0
  if (typeof color === 'string') {
    warning(!includes(DEPRECATED_BADGE_COLORS, color), WARNING_COLORS);
  }

  const isIcon = _willdeprecate$contentType === PILL_TYPE_ICON;

  if (isIcon) {
    const iconProps = { className, color, id, size, srLabel, ref, backgroundType, customVariant, ...otherProps };
    return <PillIcon {...iconProps} />;
  }

  const allProps = {
    customVariant,
    contentType: _willdeprecate$contentType,
    hierarchy,
    roundedCorners,
    size,
    ...props,
  };

  const componentId = useId(id);
  const { getThemedComponentClasses, themeHash } = useThemeContext();

  const computedColor = computeColorProps({ color });

  const classes = classNames(namespace, `${namespace}--pill`, `${namespace}--${computedColor}`, className, {
    [`${namespace}--${size}`]: size,
    [`${namespace}--${computedColor}--quiet`]: !secondaryColor && hierarchy === 'quiet',
    [`${namespace}--rounded-top-left`]: includes(roundedCorners, 'top-left'),
    [`${namespace}--rounded-top-right`]: includes(roundedCorners, 'top-right'),
    [`${namespace}--rounded-bottom-left`]: includes(roundedCorners, 'bottom-left'),
    [`${namespace}--rounded-bottom-right`]: includes(roundedCorners, 'bottom-right'),
    [`${namespace}--color-on-background`]: hierarchy === 'loud' && backgroundType === 'complexBackground',
  }, getThemedComponentClasses?.('badge', allProps));

  const andesDataAttributes = {
    'data-andes-badge': true,
    'data-andes-badge-type': 'pill',
    'data-andes-badge-hierarchy': hierarchy,
    'data-andes-badge-size': size,
    ...themeHash,
  };

  return (
    <div
      className={classes}
      id={componentId}
      ref={ref}
      {...otherProps}
      style={{ backgroundColor: secondaryColor?.background }}
      {...andesDataAttributes}
    >
      {srLabel && <VisuallyHidden>{srLabel}</VisuallyHidden>}
      {children
      && (
        <p
          aria-hidden={!!(srLabel) || undefined}
          className={`${namespace}__content`}
          style={{ color: secondaryColor?.text }}
        >
          {children}
        </p>
      )}
    </div>
  );
};

Pill.propTypes = {
  children: PropTypes.node,
  className: PropTypes.string,
  color: PropTypes.oneOf([
    'caution',
    'informative',
    'inverted',
    'negative',
    'neutral',
    'positive',
  ]),
  contentType: PropTypes.oneOf(CONTENT_TYPE),
  customVariant: PropTypes.string,
  hierarchy: PropTypes.oneOf(['loud', 'quiet']),
  id: PropTypes.string,
  roundedCorners: PropTypes.arrayOf(PropTypes.oneOf(ROUNDED_CORNERS_VALUES).isRequired),
  secondaryColor: PropTypes.shape({
    background: PropTypes.string.isRequired,
    text: PropTypes.string,
  }),
  size: PropTypes.oneOf(['xsmall', 'small', 'large']),
  srLabel: PropTypes.string,
  backgroundType: PropTypes.oneOf(['basic', 'complexBackground']),
};

Pill.displayName = 'Pill';

export default Pill;
